import { useState } from 'react';
import { supabase } from './supabaseClient';

export default function Auth({ session }) {
  const [loading, setLoading] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) alert(error.message);
    setLoading(false);
  };

  const handleSignUp = async (e) => {
    e.preventDefault();
    setLoading(true);
    const { error } = await supabase.auth.signUp({ email, password });
    if (error) alert(error.message);
    else alert("Sukses! Kontrollo emailin tënd (nëse Supabase kërkon verifikim) ose provo të logohesh.");
    setLoading(false);
  };

  return (
    <div style={{ padding: '20px', border: '1px solid #ccc', maxWidth: '400px', margin: '20px auto' }}>
      <h2>Hyr në llogari</h2>
      <p>Për të ruajtur produktet e tua, duhet të kesh një llogari.</p>
      <form>
        <input 
          type="email" 
          placeholder="Emaili yt" 
          value={email} 
          onChange={(e) => setEmail(e.target.value)} 
          style={{ display: 'block', width: '100%', marginBottom: '10px', padding: '8px' }}
        />
        <input 
          type="password" 
          placeholder="Fjalëkalimi" 
          value={password} 
          onChange={(e) => setPassword(e.target.value)} 
          style={{ display: 'block', width: '100%', marginBottom: '10px', padding: '8px' }}
        />
        <button onClick={handleLogin} disabled={loading} style={{ marginRight: '10px' }}>
          {loading ? 'Po logohet...' : 'Log In'}
        </button>
        <button onClick={handleSignUp} disabled={loading}>
          Sign Up
        </button>
      </form>
    </div>
  );
}
